public final class KeychainStore {
    public static let shared = KeychainStore()
    private init() {}

    public func getOrCreateSymmetricKey(tag: String) throws -> SymmetricKey {
        if let existing = try? read(tag: tag) {
            return SymmetricKey(data: existing)
        }
        var keyData = Data(count: 32)
        let res = keyData.withUnsafeMutableBytes { ptr in
            SecRandomCopyBytes(kSecRandomDefault, 32, ptr.baseAddress!)
        }
        guard res == errSecSuccess else { throw BankingError.keychainFailure(res) }
        try save(tag: tag, data: keyData)
        return SymmetricKey(data: keyData)
    }

    private func save(tag: String, data: Data) throws {
        let tagData = tag.data(using: .utf8) ?? Data()
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tagData,
            kSecAttrKeyType as String: kSecAttrKeyTypeAES,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else { throw BankingError.keychainFailure(status) }
    }

    private func read(tag: String) throws -> Data {
        let tagData = tag.data(using: .utf8) ?? Data()
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: tagData,
            kSecAttrKeyType as String: kSecAttrKeyTypeAES,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess else { throw BankingError.keychainFailure(status) }
        guard let data = item as? Data else { throw BankingError.cryptoFailure }
        return data
    }
}

