public protocol SecureStore {
    func load() throws -> LedgerSnapshot
    func save(_ snapshot: LedgerSnapshot) throws
}

public final class SecureFileStore: SecureStore {
    private let url: URL
    private let queue = DispatchQueue(label: "com.example.banking.securefilestore", qos: .userInitiated)

    public init(filename: String = "banking_ledger.dat") {
        let fm = FileManager.default
        let base = fm.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        let dir = base.appendingPathComponent("BankingModule", isDirectory: true)
        try? fm.createDirectory(at: dir, withIntermediateDirectories: true)
        self.url = dir.appendingPathComponent(filename)
    }

    public func load() throws -> LedgerSnapshot {
        try queue.sync {
            let fm = FileManager.default
            guard fm.fileExists(atPath: url.path) else { return LedgerSnapshot() }
            let encrypted = try Data(contentsOf: url, options: [.mappedIfSafe])
            let decrypted = try CryptoService.shared.decrypt(encrypted)
            return try JSONDecoder().decode(LedgerSnapshot.self, from: decrypted)
        }
    }

    public func save(_ snapshot: LedgerSnapshot) throws {
        try queue.sync {
            let data = try JSONEncoder().encode(snapshot)
            let encrypted = try CryptoService.shared.encrypt(data)
            do {
                try encrypted.write(to: url, options: [.atomic])
            } catch {
                throw BankingError.persistenceFailure
            }
        }
    }
}

// MARK: - Banking Engine

public final class BankingEngine {
    public private(set) var store: SecureStore
    private let lock = NSLock()

    public init(store: SecureStore = SecureFileStore()) {
        self.store = store
    }

    public func createAccount(name: String,
                              currencyCode: String = "USD",
                              initialBalanceMinor: Int64) throws -> Account {
        guard initialBalanceMinor >= 0 else { throw BankingError.invalidAmount }
        lock.lock()
        defer { lock.unlock() }
        var snap = try store.load()
        let account = Account(name: name,
                              currencyCode: currencyCode,
                              availableBalanceMinor: initialBalanceMinor,
                              ledgerBalanceMinor: initialBalanceMinor,
                              updatedAt: Date())
        snap.accounts[account.id] = account
        snap.transactionsByAccount[account.id] = []
        try store.save(snap)
        return account
    }

    public func getAccount(_ id: UUID) throws -> Account {
        lock.lock()
        defer { lock.unlock() }
        let snap = try store.load()
        guard let acc = snap.accounts[id] else { throw BankingError.accountNotFound }
        return acc
    }

    public func listAccounts() throws -> [Account] {
        lock.lock()
        defer { lock.unlock() }
        let snap = try store.load()
        return snap.accounts.values.sorted(by: { $0.updatedAt > $1.updatedAt })
    }

    public func listTransactions(accountID: UUID) throws -> [Transaction] {
        lock.lock()
        defer { lock.unlock() }
        let snap = try store.load()
        guard snap.accounts[accountID] != nil else { throw BankingError.accountNotFound }
        return (snap.transactionsByAccount[accountID] ?? []).sorted(by: { $0.createdAt > $1.createdAt })
    }

    public func processTransaction(accountID: UUID,
                                   type: TransactionType,
                                   amountMinor: Int64,
                                   description: String,
                                   idempotencyKey: String? = nil) throws -> Transaction {
        guard amountMinor > 0 else { throw BankingError.invalidAmount }

        lock.lock()
        defer { lock.unlock() }

        var snap = try store.load()
        guard var account = snap.accounts[accountID] else { throw BankingError.accountNotFound }

        if let key = idempotencyKey {
            if snap.appliedIdempotencyKeys.contains(key) { throw BankingError.idempotencyConflict }
        }

        let delta: Int64
        switch type {
        case .credit: delta = amountMinor
        case .debit: delta = -amountMinor
        }

        let newAvailable = account.availableBalanceMinor &+ delta
        let newLedger = account.ledgerBalanceMinor &+ delta

        if type == .debit && newAvailable < 0 {
            throw BankingError.insufficientFunds
        }

        account.availableBalanceMinor = newAvailable
        account.ledgerBalanceMinor = newLedger
        account.updatedAt = Date()

        let txn = Transaction(accountID: accountID,
                              type: type,
                              amountMinor: amountMinor,
                              description: description,
                              createdAt: Date(),
                              idempotencyKey: idempotencyKey)

        snap.accounts[accountID] = account
        snap.transactionsByAccount[accountID, default: []].append(txn)
        if let key = idempotencyKey { snap.appliedIdempotencyKeys.insert(key) }

        try store.save(snap)
        return txn
    }
}

// MARK: - Formatting

public struct MoneyFormatter {
    public static func string(minor: Int64, currencyCode: String, locale: Locale = .current) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currencyCode
        formatter.locale = locale
        formatter.maximumFractionDigits = 2
        formatter.minimumFractionDigits = 2
        let major = Decimal(minor) / 100
        return formatter.string(from: major as NSDecimalNumber) ?? "\(currencyCode) \(major)"
    }
}

