@MainActor
public final class AccountsViewModel: ObservableObject {
    @Published public private(set) var accounts: [Account] = []
    @Published public private(set) var selectedAccount: Account?
    @Published public private(set) var transactions: [Transaction] = []
    @Published public private(set) var lastError: String?

    private let engine: BankingEngine

    public init(engine: BankingEngine = BankingEngine()) {
        self.engine = engine
    }

    public func refresh() {
        do {
            lastError = nil
            accounts = try engine.listAccounts()
            if let sel = selectedAccount, let refreshed = accounts.first(where: { $0.id == sel.id }) {
                selectedAccount = refreshed
                transactions = try engine.listTransactions(accountID: sel.id)
            }
        } catch {
            lastError = (error as? LocalizedError)?.errorDescription ?? "\(error)"
        }
    }

    public func selectAccount(_ account: Account) {
        do {
            lastError = nil
            selectedAccount = try engine.getAccount(account.id)
            transactions = try engine.listTransactions(accountID: account.id)
        } catch {
            lastError = (error as? LocalizedError)?.errorDescription ?? "\(error)"
        }
    }

    public func createAccount(name: String, currencyCode: String = "USD", initialBalanceMinor: Int64) {
        do {
            lastError = nil
            let acc = try engine.createAccount(name: name, currencyCode: currencyCode, initialBalanceMinor: initialBalanceMinor)
            selectedAccount = acc
            refresh()
        } catch {
            lastError = (error as? LocalizedError)?.errorDescription ?? "\(error)"
        }
    }

    public func credit(amountMinor: Int64, description: String, idempotencyKey: String? = nil) {
        guard let acc = selectedAccount else { return }
        do {
            lastError = nil
            _ = try engine.processTransaction(accountID: acc.id, type: .credit, amountMinor: amountMinor, description: description, idempotencyKey: idempotencyKey)
            selectAccount(acc)
            refresh()
        } catch {
            lastError = (error as? LocalizedError)?.errorDescription ?? "\(error)"
        }
    }

    public func debit(amountMinor: Int64, description: String, idempotencyKey: String? = nil) {
        guard let acc = selectedAccount else { return }
        do {
            lastError = nil
            _ = try engine.processTransaction(accountID: acc.id, type: .debit, amountMinor: amountMinor, description: description, idempotencyKey: idempotencyKey)
            selectAccount(acc)
            refresh()
        } catch {
            lastError = (error as? LocalizedError)?.errorDescription ?? "\(error)"
        }
    }

    public func balanceString(for account: Account, locale: Locale = .current) -> String {
        MoneyFormatter.string(minor: account.availableBalanceMinor, currencyCode: account.currencyCode, locale: locale)
    }
